<template><div><h1 id="rag-chunk-知识" tabindex="-1"><a class="header-anchor" href="#rag-chunk-知识"><span>RAG Chunk 知识</span></a></h1>
<p>Chunk 的目标不是“切得越碎越好”，而是让每个片段既能保留上下文，又方便检索命中。</p>
<h2 id="一、基础切分" tabindex="-1"><a class="header-anchor" href="#一、基础切分"><span>一、基础切分</span></a></h2>
<h3 id="_1-固定长度切分" tabindex="-1"><a class="header-anchor" href="#_1-固定长度切分"><span>1. 固定长度切分</span></a></h3>
<p>最简单的方式，按字符数、词数或 token 数硬切。</p>
<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">chunkTextByFixedLength</span><span class="token punctuation">(</span>text<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span> rawOptions<span class="token operator">:</span> Pick<span class="token operator">&lt;</span>ChunkingOptions<span class="token punctuation">,</span> <span class="token string">"chunkSize"</span> <span class="token operator">|</span> <span class="token string">"chunkOverlap"</span><span class="token operator">></span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">const</span> options <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token operator">...</span><span class="token constant">DEFAULT_OPTIONS</span><span class="token punctuation">,</span> <span class="token operator">...</span>rawOptions <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> normalizedText <span class="token operator">=</span> <span class="token function">normalizeLineEndings</span><span class="token punctuation">(</span>text<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>normalizedText<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">return</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">const</span> chunks<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">let</span> cursor <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">while</span> <span class="token punctuation">(</span>cursor <span class="token operator">&lt;</span> normalizedText<span class="token punctuation">.</span>length<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">const</span> end <span class="token operator">=</span> Math<span class="token punctuation">.</span><span class="token function">min</span><span class="token punctuation">(</span>normalizedText<span class="token punctuation">.</span>length<span class="token punctuation">,</span> cursor <span class="token operator">+</span> options<span class="token punctuation">.</span>chunkSize<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token keyword">const</span> chunk <span class="token operator">=</span> normalizedText<span class="token punctuation">.</span><span class="token function">slice</span><span class="token punctuation">(</span>cursor<span class="token punctuation">,</span> end<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>chunk<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">			chunks<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>chunk<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>end <span class="token operator">>=</span> normalizedText<span class="token punctuation">.</span>length<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">			<span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">		cursor <span class="token operator">=</span> Math<span class="token punctuation">.</span><span class="token function">max</span><span class="token punctuation">(</span>end <span class="token operator">-</span> options<span class="token punctuation">.</span>chunkOverlap<span class="token punctuation">,</span> cursor <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> chunks<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre>
<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>适用场景</strong></p>
<ul>
<li>先把系统跑起来</li>
<li>文档结构不明显</li>
<li>对稳定性要求高于召回质量</li>
</ul>
<h3 id="_2-递归切分" tabindex="-1"><a class="header-anchor" href="#_2-递归切分"><span>2. 递归切分</span></a></h3>
<p>先按大结构切，再逐层细分，直到满足长度限制。</p>
<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">chunkTextRecursively</span><span class="token punctuation">(</span></span>
<span class="line">	text<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span></span>
<span class="line">	rawOptions<span class="token operator">:</span> Pick<span class="token operator">&lt;</span>ChunkingOptions<span class="token punctuation">,</span> <span class="token string">"chunkSize"</span> <span class="token operator">|</span> <span class="token string">"chunkOverlap"</span><span class="token operator">></span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">const</span> options <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token operator">...</span><span class="token constant">DEFAULT_OPTIONS</span><span class="token punctuation">,</span> <span class="token operator">...</span>rawOptions <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> normalizedText <span class="token operator">=</span> <span class="token function">normalizeLineEndings</span><span class="token punctuation">(</span>text<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>normalizedText<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">return</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> <span class="token function">splitByHierarchy</span><span class="token punctuation">(</span>normalizedText<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token string">"\n\n"</span><span class="token punctuation">,</span> <span class="token string">"\n"</span><span class="token punctuation">,</span> <span class="token string">". "</span><span class="token punctuation">,</span> <span class="token string">"? "</span><span class="token punctuation">,</span> <span class="token string">"! "</span><span class="token punctuation">,</span> <span class="token string">"; "</span><span class="token punctuation">,</span> <span class="token string">" "</span><span class="token punctuation">,</span> <span class="token string">""</span><span class="token punctuation">]</span><span class="token punctuation">,</span> options<span class="token punctuation">.</span>chunkSize<span class="token punctuation">,</span> options<span class="token punctuation">.</span>chunkOverlap<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre>
<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-基于句子的切分" tabindex="-1"><a class="header-anchor" href="#_3-基于句子的切分"><span>3. 基于句子的切分</span></a></h3>
<p>按句号、问号、分号等边界切分，再按长度控制合并。</p>
<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">chunkTextBySentence</span><span class="token punctuation">(</span>text<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">const</span> normalized <span class="token operator">=</span> <span class="token function">normalizeLineEndings</span><span class="token punctuation">(</span>text<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>normalized<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">return</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">const</span> sentences <span class="token operator">=</span> <span class="token function">isChineseDominant</span><span class="token punctuation">(</span>normalized<span class="token punctuation">)</span> <span class="token operator">?</span> <span class="token function">splitChineseSentences</span><span class="token punctuation">(</span>normalized<span class="token punctuation">)</span> <span class="token operator">:</span> <span class="token function">splitEnglishSentences</span><span class="token punctuation">(</span>normalized<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">return</span> sentences<span class="token punctuation">.</span>length <span class="token operator">></span> <span class="token number">0</span> <span class="token operator">?</span> sentences <span class="token operator">:</span> <span class="token punctuation">[</span>normalized<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre>
<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="二、结构切分" tabindex="-1"><a class="header-anchor" href="#二、结构切分"><span>二、结构切分</span></a></h2>
<h3 id="_1-markdown-切分" tabindex="-1"><a class="header-anchor" href="#_1-markdown-切分"><span>1. Markdown 切分</span></a></h3>
<p>按标题层级、段落、代码块切。</p>
<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">buildMarkdownRagIngestBody</span><span class="token punctuation">(</span>input<span class="token operator">:</span> ChunkDocumentInput<span class="token punctuation">,</span> rawOptions<span class="token operator">:</span> ChunkingOptions <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token operator">:</span> RagIngestBody <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">const</span> options <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token operator">...</span><span class="token constant">DEFAULT_OPTIONS</span><span class="token punctuation">,</span> <span class="token operator">...</span>rawOptions <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> cleanedContent <span class="token operator">=</span> <span class="token function">normalizeMarkdownContent</span><span class="token punctuation">(</span>input<span class="token punctuation">.</span>content<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> title <span class="token operator">=</span> input<span class="token punctuation">.</span>title<span class="token operator">?.</span><span class="token function">trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">||</span> <span class="token function">extractTitle</span><span class="token punctuation">(</span>cleanedContent<span class="token punctuation">,</span> input<span class="token punctuation">.</span>relativePath<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> documentId <span class="token operator">=</span> <span class="token function">buildDocumentId</span><span class="token punctuation">(</span>input<span class="token punctuation">.</span>relativePath<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> sections <span class="token operator">=</span> <span class="token function">splitIntoSections</span><span class="token punctuation">(</span>cleanedContent<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> chunks<span class="token operator">:</span> RagIngestBody<span class="token punctuation">[</span><span class="token string">"chunks"</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">let</span> nextChunkIndex <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> section <span class="token keyword">of</span> sections<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">const</span> result <span class="token operator">=</span> <span class="token function">chunkSection</span><span class="token punctuation">(</span>section<span class="token punctuation">,</span> documentId<span class="token punctuation">,</span> input<span class="token punctuation">.</span>relativePath<span class="token punctuation">,</span> options<span class="token punctuation">,</span> nextChunkIndex<span class="token punctuation">,</span> input<span class="token punctuation">.</span>metadata<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		chunks<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token operator">...</span>result<span class="token punctuation">.</span>chunks<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		nextChunkIndex <span class="token operator">=</span> result<span class="token punctuation">.</span>nextChunkIndex<span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> <span class="token function">assembleRagIngestBody</span><span class="token punctuation">(</span></span>
<span class="line">		<span class="token punctuation">{</span></span>
<span class="line">			documentId<span class="token punctuation">,</span></span>
<span class="line">			namespace<span class="token operator">:</span> options<span class="token punctuation">.</span>namespace<span class="token punctuation">,</span></span>
<span class="line">			title<span class="token punctuation">,</span></span>
<span class="line">			metadata<span class="token operator">:</span> input<span class="token punctuation">.</span>metadata<span class="token punctuation">,</span></span>
<span class="line">		<span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">		chunks<span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre>
<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">function</span> <span class="token function">chunkSection</span><span class="token punctuation">(</span></span>
<span class="line">	section<span class="token operator">:</span> MarkdownSection<span class="token punctuation">,</span></span>
<span class="line">	documentId<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span></span>
<span class="line">	relativePath<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span></span>
<span class="line">	options<span class="token operator">:</span> Required<span class="token operator">&lt;</span>Pick<span class="token operator">&lt;</span>ChunkingOptions<span class="token punctuation">,</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"namespace"</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"targetChineseChars"</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"maxChineseChars"</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"overlapChineseChars"</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"targetEnglishWords"</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"maxEnglishWords"</span></span>
<span class="line">		<span class="token operator">|</span> <span class="token string">"overlapEnglishWords"</span></span>
<span class="line">	<span class="token operator">>></span><span class="token punctuation">,</span></span>
<span class="line">	startChunkIndex<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">,</span></span>
<span class="line">	metadata<span class="token operator">?</span><span class="token operator">:</span> RagMetadata<span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token punctuation">{</span> chunks<span class="token operator">:</span> RagIngestBody<span class="token punctuation">[</span><span class="token string">"chunks"</span><span class="token punctuation">]</span><span class="token punctuation">;</span> nextChunkIndex<span class="token operator">:</span> <span class="token builtin">number</span> <span class="token punctuation">}</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">const</span> chunks<span class="token operator">:</span> RagIngestBody<span class="token punctuation">[</span><span class="token string">"chunks"</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> sectionPath <span class="token operator">=</span> section<span class="token punctuation">.</span>headingPath<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token string">" > "</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">let</span> chunkIndex <span class="token operator">=</span> startChunkIndex<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> block <span class="token keyword">of</span> section<span class="token punctuation">.</span>blocks<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">const</span> parts <span class="token operator">=</span> <span class="token function">splitBlock</span><span class="token punctuation">(</span>block<span class="token punctuation">,</span> options<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> part <span class="token keyword">of</span> parts<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">			<span class="token keyword">const</span> text <span class="token operator">=</span> part<span class="token punctuation">.</span><span class="token function">trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">			<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>text<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">				<span class="token keyword">continue</span><span class="token punctuation">;</span></span>
<span class="line">			<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">			chunks<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">				chunkId<span class="token operator">:</span> <span class="token template-string"><span class="token template-punctuation string">`</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">${</span>documentId<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">:</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">${</span><span class="token function">String</span><span class="token punctuation">(</span>chunkIndex<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">padStart</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token string">"0"</span><span class="token punctuation">)</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">`</span></span><span class="token punctuation">,</span></span>
<span class="line">				index<span class="token operator">:</span> chunkIndex<span class="token punctuation">,</span></span>
<span class="line">				text<span class="token punctuation">,</span></span>
<span class="line">				metadata<span class="token operator">:</span> <span class="token function">buildChunkMetadata</span><span class="token punctuation">(</span>relativePath<span class="token punctuation">,</span> sectionPath<span class="token punctuation">,</span> text<span class="token punctuation">,</span> metadata<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">			<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
