<span class="line">		<span class="token punctuation">}</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> <span class="token punctuation">{</span></span>
<span class="line">		chunks<span class="token operator">:</span> <span class="token function">mergeTinyTailChunks</span><span class="token punctuation">(</span>chunks<span class="token punctuation">,</span> options<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">		nextChunkIndex<span class="token operator">:</span> chunkIndex<span class="token punctuation">,</span></span>
<span class="line">	<span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
