<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">buildDialogueRagIngestBody</span><span class="token punctuation">(</span>input<span class="token operator">:</span> ChunkDocumentInput<span class="token punctuation">,</span> rawOptions<span class="token operator">:</span> ChunkingOptions <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token operator">:</span> RagIngestBody <span class="token punctuation">{</span></span>
