<span class="line">	<span class="token keyword">const</span> turns <span class="token operator">=</span> <span class="token function">parseDialogueTurns</span><span class="token punctuation">(</span>content<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> chunks <span class="token operator">=</span> <span class="token function">groupDialogueTurns</span><span class="token punctuation">(</span>turns<span class="token punctuation">,</span> options<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span><span class="token punctuation">(</span>text<span class="token punctuation">,</span> index<span class="token punctuation">)</span> <span class="token operator">=></span> <span class="token function">createRagChunk</span><span class="token punctuation">(</span>documentId<span class="token punctuation">,</span> index<span class="token punctuation">,</span> text<span class="token punctuation">,</span> input<span class="token punctuation">.</span>metadata<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
