<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三、语义切分" tabindex="-1"><a class="header-anchor" href="#三、语义切分"><span>三、语义切分</span></a></h2>
<h3 id="_1-语义切分" tabindex="-1"><a class="header-anchor" href="#_1-语义切分"><span>1. 语义切分</span></a></h3>
