<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">semanticChunkParagraphs</span><span class="token punctuation">(</span>paragraphs<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span> options<span class="token operator">:</span> Pick<span class="token operator">&lt;</span>ChunkingOptions<span class="token punctuation">,</span> <span class="token string">"semanticThreshold"</span> <span class="token operator">|</span> <span class="token string">"chunkSize"</span> <span class="token operator">|</span> <span class="token string">"chunkOverlap"</span><span class="token operator">></span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">{</span></span>
<span class="line">	<span class="token keyword">const</span> mergedParagraphs<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> threshold <span class="token operator">=</span> options<span class="token punctuation">.</span>semanticThreshold <span class="token operator">??</span> <span class="token constant">DEFAULT_OPTIONS</span><span class="token punctuation">.</span>semanticThreshold<span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> targetSize <span class="token operator">=</span> options<span class="token punctuation">.</span>chunkSize <span class="token operator">??</span> <span class="token constant">DEFAULT_OPTIONS</span><span class="token punctuation">.</span>chunkSize<span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">const</span> overlap <span class="token operator">=</span> options<span class="token punctuation">.</span>chunkOverlap <span class="token operator">??</span> <span class="token constant">DEFAULT_OPTIONS</span><span class="token punctuation">.</span>chunkOverlap<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">let</span> current<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token keyword">let</span> currentKeywords<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> paragraph <span class="token keyword">of</span> paragraphs<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		<span class="token keyword">const</span> paragraphKeywords <span class="token operator">=</span> <span class="token function">extractKeywords</span><span class="token punctuation">(</span>paragraph<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token keyword">const</span> similarity <span class="token operator">=</span> currentKeywords<span class="token punctuation">.</span>length <span class="token operator">></span> <span class="token number">0</span> <span class="token operator">?</span> <span class="token function">jaccardSimilarity</span><span class="token punctuation">(</span>currentKeywords<span class="token punctuation">,</span> paragraphKeywords<span class="token punctuation">)</span> <span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token keyword">const</span> candidate <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token operator">...</span>current<span class="token punctuation">,</span> paragraph<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>candidate<span class="token punctuation">.</span>length <span class="token operator">&lt;=</span> targetSize <span class="token operator">&amp;&amp;</span> similarity <span class="token operator">>=</span> threshold<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">			current <span class="token operator">=</span> candidate<span class="token punctuation">;</span></span>
<span class="line">			currentKeywords <span class="token operator">=</span> <span class="token function">extractKeywords</span><span class="token punctuation">(</span>current<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token string">"\n\n"</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">			<span class="token keyword">continue</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">		<span class="token keyword">if</span> <span class="token punctuation">(</span>current<span class="token punctuation">.</span>length <span class="token operator">></span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">			mergedParagraphs<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>current<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token string">"\n\n"</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">		current <span class="token operator">=</span> current<span class="token punctuation">.</span>length <span class="token operator">></span> <span class="token number">0</span> <span class="token operator">&amp;&amp;</span> overlap <span class="token operator">></span> <span class="token number">0</span> <span class="token operator">?</span> current<span class="token punctuation">.</span><span class="token function">slice</span><span class="token punctuation">(</span><span class="token operator">-</span>overlap<span class="token punctuation">)</span> <span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">		current<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>paragraph<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">		currentKeywords <span class="token operator">=</span> <span class="token function">extractKeywords</span><span class="token punctuation">(</span>current<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token string">"\n\n"</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">if</span> <span class="token punctuation">(</span>current<span class="token punctuation">.</span>length <span class="token operator">></span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">		mergedParagraphs<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>current<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token string">"\n\n"</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">	<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">	<span class="token keyword">return</span> mergedParagraphs<span class="token punctuation">.</span><span class="token function">filter</span><span class="token punctuation">(</span>Boolean<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre>
